      {
        "front": "Apa itu bahan pembinaan?",
        "back": "Bahan pembinaan adalah elemen asas dalam setiap projek pembinaan, termasuk kayu, batu, konkrit, dan logam."
      },
      {
        "front": "Sebutkan satu kelebihan kayu sebagai bahan pembinaan.",
        "back": "Kelebihan kayu adalah ia ringan dan mudah diproses, menjadikannya pilihan popular dalam pembinaan rumah."
      },
      {
        "front": "Mengapa konkrit sering digunakan dalam pembinaan?",
        "back": "Konkrit kuat dan tahan lama, menjadikannya ideal untuk struktur yang memerlukan ketahanan tinggi."
      },
      {
        "front": "Apa perbezaan antara batu dan logam sebagai bahan pembinaan?",
        "back": "Batu adalah bahan semula jadi yang tahan lama, manakala logam lebih kuat dan fleksibel, sesuai untuk struktur yang memerlukan sokongan berat."
      }
    ]
  }
